def e0_series():
    """Laurent series of (x, y) at the E0-places O, T, T' with uniformizer s."""
    out = {}
    # T = (0,0): uniformizer x = s; y = s^3*(series): y(y+2x+1) = x^3 =>
    # y = x^3/(1+2x+y): iterate.
    y = s**_sage_const_3 
    for _ in range(NTRUNC + _sage_const_2 ):
        y = s**_sage_const_3  / (_sage_const_1  + _sage_const_2 *s + y)
    out['T'] = (s + O(s**NTRUNC), y + O(s**NTRUNC))
    # T' = (0,-1): x = s; y = -1 + w, w(w-1+2s... ) solve G: (w-1)^2+2s(w-1)+(w-1)
    # -s^3 = 0 -> w^2 - w + 2sw - 2s - s^3 = 0 => w = (2s + s^3 + w^2 + 2sw... )
    # iterate w = 2s + s^3 - 2*s*w + ... from w^2 - (1-2s) w + ... rearranged:
    # w = (2s + s^3 + w^2)/(1 - 2s)?? derive: G(x,-1+w) = (-1+w)^2 + 2x(-1+w)
    # + (-1+w) - x^3 = 1 - 2w + w^2 - 2x + 2xw - 1 + w - x^3 = w^2 + w(2x - 1)
    # - 2x - x^3. So w = (2x + x^3 - w^2)/(2x - 1)*(-1)... w(2x-1) = 2x + x^3 - w^2
    # => w = (2x + x^3 - w^2)/(2x - 1).
    w = _sage_const_0 *s
    for _ in range(NTRUNC + _sage_const_2 ):
        w = (_sage_const_2 *s + s**_sage_const_3  - w**_sage_const_2 ) / (_sage_const_2 *s - _sage_const_1 )
    out['Tp'] = (s + O(s**NTRUNC), -_sage_const_1  + w + O(s**NTRUNC))
    # O: x = s^-2 * X, y = s^-3 * Y with X,Y units; standard: set x = 1/s^2 + a1/s
    # + ...: iterate curve for y ~ -? choose y-leading: y^2 ~ x^3 => y = ±s^-3(1+..).
    # Parametrize by z = x/y (uniformizer at O): x = z^-2*(series in z)?? Use:
    # w = -x/y => y = -x/w; plug: x^2/w^2 - 2x^2/w - x/w = x^3 =>
    # x/w^2 - 2x/w - 1/w = x^2 => x^2 - x(1/w^2 - 2/w) + 1/w = 0... messy; instead
    # iterate directly: y = -x/w with w = s (the uniformizer), and curve gives
    # x = (y^2 + 2xy + y)/x^2 ... choose the classical: at O, u0 = x/y has a simple
    # zero; x = u0^{-2}*h, y = u0^{-3}*h for SOME common h: from y = x/u0:
    # x^2/u0^2 + 2x^2/u0 + x/u0 = x^3 => 1/u0^2 + 2x/u0... divide x^2:
    # (1/u0^2) + (2/u0)x/x... redo: y = x/u0: G: x^2/u0^2 + 2x*x/u0 + x/u0 - x^3 = 0
    # divide by x: x/u0^2 + 2x/u0*... => x/u0^2 + 2x^2/u0 + 1/u0 = x^2?? checking:
    # (x/u0)^2 = x^2/u0^2: G = x^2/u0^2 + 2x^2/u0 + x/u0 - x^3 = 0; divide x^2:
    # 1/u0^2 + 2/u0 + 1/(x u0) = x. So x = 1/u0^2 + 2/u0 + 1/(x*u0): iterate x.
    xO = s**-_sage_const_2 
    for _ in range(NTRUNC + _sage_const_4 ):
        xO = s**-_sage_const_2  + _sage_const_2 *s**-_sage_const_1  + _sage_const_1 /(xO*s)
    yO = xO/s
    out['O'] = (xO + O(s**(NTRUNC-_sage_const_4 )), yO + O(s**(NTRUNC-_sage_const_5 )))
    return out


def cubic_branches(xs, ys):
    """Branches of u^3 + x*u + (y+1) = 0 over a base place, as Laurent series:
    Newton-polygon slopes, leading equation solved over F, then Hensel."""
    B = ys + _sage_const_1 
    vx, vB = xs.valuation(), B.valuation()
    ax = xs.coefficients()[_sage_const_0 ]
    aB = B.coefficients()[_sage_const_0 ]
    branches = []
    for v in range(-_sage_const_6 , _sage_const_7 ):
        vals = [_sage_const_3 *v, v + vx, vB]
        m = min(vals)
        idx = [k for k in range(_sage_const_3 ) if vals[k] == m]
        if len(idx) < _sage_const_2 :
            continue
        P = PolynomialRing(F, names=('cc',)); (cc,) = P._first_ngens(1)
        poly = P(_sage_const_0 )
        if _sage_const_0  in idx:
            poly += cc**_sage_const_3 
        if _sage_const_1  in idx:
            poly += ax*cc
        if _sage_const_2  in idx:
            poly += aB
        for c, _ in poly.roots():
            if c == _sage_const_0 :
                continue
            u = c * s**v
            for _ in range(NTRUNC + _sage_const_4 ):
                fu = u**_sage_const_3  + xs*u + B
                if fu == _sage_const_0 :
                    break
                dfu = _sage_const_3 *u**_sage_const_2  + xs
                u = u - fu/dfu
            res = u**_sage_const_3  + xs*u + B
            if res != _sage_const_0  and res.valuation() < NTRUNC - _sage_const_8 :
                continue
            new = True
            for b in branches:
                d = u - b
                if d == _sage_const_0  or d.valuation() >= NTRUNC//_sage_const_2 :
                    new = False
            if new:
                branches.append(u)
    return branches


def cube_root_series(ys):
    """One cube root of the series ys over F (leading coeff root via polynomial)."""
    v = ys.valuation()
    assert v % _sage_const_3  == _sage_const_0 
    lead = ys.coefficients()[_sage_const_0 ]
    P = PolynomialRing(F, names=('z',)); (z,) = P._first_ngens(1)
    rts = (z**_sage_const_3  - lead).roots()
    if not rts:
        return None
    t = rts[_sage_const_0 ][_sage_const_0 ] * s**(v//_sage_const_3 )
    for _ in range(NTRUNC + _sage_const_4 ):
        ft = t**_sage_const_3  - ys
        if ft == _sage_const_0 :
            break
        t = t - ft/(_sage_const_3 *t**_sage_const_2 )
    return t


