# --- battery over sampled Dt configurations
def battery(nsamples=_sage_const_20 ):
    results = []
    configs = []
    percfg = [(('d', a),) for a in range(_sage_const_3 )] +              [(('p', a, b),) for a, b in itertools.combinations(range(_sage_const_3 ), _sage_const_2 )]
    # a configuration: for each u-branch i in 0..2 pick doubled point (d,k) or pair
    # (p,k1,k2) among its 3 t-points
    choices = []
    for i in range(_sage_const_3 ):
        c = [('d', k) for k in range(_sage_const_3 )] +             [('p', k1, k2) for k1, k2 in itertools.combinations(range(_sage_const_3 ), _sage_const_2 )]
        choices.append(c)
    allcfg = list(itertools.product(*choices))
    random.shuffle(allcfg)
    for cfg in allcfg[:nsamples]:
        allowL = {}
        for i, ch in enumerate(cfg):
            if ch[_sage_const_0 ] == 'd':
                allowL[_sage_const_3 *i + ch[_sage_const_1 ]] = _sage_const_2 
            else:
                allowL[_sage_const_3 *i + ch[_sage_const_1 ]] = _sage_const_1 
                allowL[_sage_const_3 *i + ch[_sage_const_2 ]] = _sage_const_1 
        KL = space_dim_and_basis(allowL, False)
        allowW = {k: -v for k, v in allowL.items()}
        KW = space_dim_and_basis(allowW, True)
        results.append((cfg, KL.nrows(), KW.nrows(), KL, KW))
    return results


