def random_points(n):
    pts = []
    tries = _sage_const_0 
    while len(pts) < n and tries < _sage_const_4000 :
        tries += _sage_const_1 
        x0 = F.random_element()
        # y from E0
        Ry = PolynomialRing(F, names=('Y',)); (Y,) = Ry._first_ngens(1)
        yr = (Y**_sage_const_2  + _sage_const_2 *x0*Y + Y - x0**_sage_const_3 ).roots()
        if not yr:
            continue
        y0 = yr[_sage_const_0 ][_sage_const_0 ]
        ur = (Y**_sage_const_3  + x0*Y + (y0 + _sage_const_1 )).roots()
        if not ur:
            continue
        u0 = ur[_sage_const_0 ][_sage_const_0 ]
        tr = (Y**_sage_const_3  - y0).roots()
        if not tr:
            continue
        t0 = tr[_sage_const_0 ][_sage_const_0 ]
        pts.append((x0, y0, u0, t0))
    return pts


