def evalvec(coeffvec, pt):
    x0, y0, u0, t0 = pt
    v = F(_sage_const_0 )
    for c, (p, q, i, j) in zip(coeffvec, FULLMONS):
        if c:
            v += c * x0**p * y0**q * u0**i * t0**j
    return v


